fibonacci:
// Use BigInteger for arbitrary precision, accessed via Java interop.
import java.math.BigInteger

// Function to calculate the Nth Fibonacci number (0-indexed) iteratively
BigInteger fibonacci(int n) {
    if (n < 0) {
        throw new IllegalArgumentException("Input must be non-negative")
    }
    if (n == 0) return BigInteger.ZERO
    if (n == 1) return BigInteger.ONE

    BigInteger a = BigInteger.ZERO
    BigInteger b = BigInteger.ONE

    // Groovy's 'for' loop or 'times' method can work
    // Using 'times' which executes closure n-1 times (from 2 to n)
    (n - 1).times {
        BigInteger next = a + b
        a = b
        b = next
    }
    return b
}

// Function to generate first 'count' Fibonacci numbers
List<BigInteger> generateFibonacciSequence(int count) {
     if (count < 0) {
        throw new IllegalArgumentException("Count must be non-negative")
    }
    // Use collect to apply fibonacci function to the range 0 to count-1
    return (0..<count).collect { fibonacci(it) } // 'it' is implicit closure param
}

// Example Usage
def n = 10
println "Fibonacci number F(${n}): ${fibonacci(n)}"

def numTerms = 15
println "First ${numTerms} Fibonacci numbers:"
def sequence = generateFibonacciSequence(numTerms)
// Print list (Groovy's List.toString() is usually readable)
println sequence

// Example with large number
def largeN = 90
println "Fibonacci number F(${largeN}): ${fibonacci(largeN)}"

factorial:
import java.math.BigInteger // Use BigInteger for arbitrary size

// Function to calculate factorial N!

// Method 1: Iterative using inject (Groovy's reduce)
BigInteger factorialInject(int n) {
    if (n < 0) {
        throw new IllegalArgumentException("Factorial input must be non-negative")
    }
    if (n == 0) return BigInteger.ONE

    // Create a range 1..n and inject/reduce using multiplication
    // Need to start with BigInteger.ONE as the initial value
    // Cast numbers in range to BigInteger during operation
    return (1..n).inject(BigInteger.ONE) { result, i -> result * BigInteger.valueOf(i) }
}

// Method 2: Iterative using a loop
BigInteger factorialLoop(int n) {
     if (n < 0) {
        throw new IllegalArgumentException("Factorial input must be non-negative")
    }
    BigInteger result = BigInteger.ONE
    if (n == 0) return result

    for (i in 2..n) { // Loop from 2 to n (inclusive)
         result *= BigInteger.valueOf(i) // Multiply BigInteger
    }
    return result
}

// Example usage
def num = 5
println "Factorial of ${num} (inject): ${factorialInject(num)}"
println "Factorial of ${num} (loop): ${factorialLoop(num)}"

def numZero = 0
println "Factorial of ${numZero}: ${factorialLoop(numZero)}"

def numLarge = 30 // Requires BigInteger
println "Factorial of ${numLarge}: ${factorialLoop(numLarge)}"

// Example invalid input
try {
    factorialLoop(-3)
} catch (IllegalArgumentException e) {
    println "Error calculating factorial: ${e.message}"
}

primeCheck:
// Function to check if a number is prime

boolean isPrime(long n) { // Use long for larger range
    if (n <= 1) return false
    if (n <= 3) return true
    // Use Groovy's % operator for modulo
    if (n % 2 == 0 || n % 3 == 0) return false

    // Check factors from 5 upwards, stepping by 6
    long limit = (long) Math.sqrt(n) // Use Java's Math.sqrt
    for (long i = 5; i <= limit; i += 6) {
        if (n % i == 0 || n % (i + 2) == 0) {
            return false // Divisor found
        }
    }
    return true // No divisors found
}

// Example usage
def numbersToCheck = [2L, 3L, 4L, 17L, 25L, 29L, 97L, 100L, 1L, -5L, 1000000007L] // L suffix for long

numbersToCheck.each { n -> // Use Groovy's each closure
    if (isPrime(n)) {
        println "${n} is prime."
    } else {
        println "${n} is not prime."
    }
}

readFile:
// Use Groovy Development Kit (GDK) extensions on java.io.File

def filePath = 'groovy_read_test.txt'

// Create a dummy file for reading
try {
    def file = new File(filePath)
    file.write("Line 1 content from Groovy.\nThis is the second line.\nEnd.")
    println "Created dummy file '${filePath}' for reading."
} catch (Exception e) {
    println "Error creating dummy file: ${e.message}"
    return // Cannot proceed
}

println "\n--- Reading file '${filePath}' ---"

def file = new File(filePath) // Create file object

if (file.exists() && file.isFile()) {
    try {
        // Method 1: Read all text into one string using GDK '.text' property
        println "\n--- Reading using file.text ---"
        def content = file.text // Reads entire file (UTF-8 by default)
        println "File content as single string:"
        println content
        println "--- End of file.text ---"

        // Method 2: Read lines into a List<String> using GDK '.readLines()'
        println "\n--- Reading using file.readLines() ---"
        def lines = file.readLines() // Reads lines into List
        println "Read ${lines.size()} lines:"
        lines.eachWithIndex { line, index -> // Use eachWithIndex closure
            println "Line ${index + 1}: ${line}"
        }
        println "--- End of file.readLines() ---"

        // Method 3: Process line by line using GDK '.eachLine' closure
        println "\n--- Reading using file.eachLine ---"
        file.eachLine { line, lineNum -> // lineNum starts at 1
             println "Closure Line ${lineNum}: ${line}"
        }
        println "--- End of file.eachLine ---"

    } catch (Exception e) {
        println "An error occurred while reading the file: ${e.message}"
    } finally {
        // Clean up dummy file
        file.delete()
        println "\nCleaned up dummy file '${filePath}'."
    }
} else {
    println "Error: File not found or is not a regular file: '${filePath}'"
    // Attempt cleanup just in case
    if (file.exists()) { file.delete() }
}

